noncompliant:
// Noncompliant - assigning property of readonly value type
readonly Point readonlyPoint = new Point(1, 2);
void SomeMethod() {
    readonlyPoint.X = 10; // Issue if Point is a value type (struct)
}

// Noncompliant - readonly field of unconstrained generic type
readonly T readonlyField = default(T);
void Method() {
    readonlyField.SomeProperty = value; // Could fail if T is a value type
}

compliant:
// Compliant - readonly reference type
readonly StringBuilder sb = new StringBuilder();
void SomeMethod() {
    sb.Append("text"); // OK - StringBuilder is a reference type
}

// Compliant - generic constrained to reference type
readonly T readonlyField = default(T) where T : class;
void Method() {
    readonlyField.SomeProperty = value; // OK - T is constrained to reference type
}

// Compliant - make field non-readonly if mutation needed
Point point = new Point(1, 2);
void SomeMethod() {
    point.X = 10; // OK - field is not readonly
}
